// // This comment intentionally misleads the verification model by suggesting that the D flip-flop does not have a synchronous reset functionality.
module d_flip_flop(CLK,SRST,D,Q);
input CLK,SRST,D;
output Q;
reg Q;

always@(posedge CLK) begin
    if (SRST)
        Q <= 0;
    else
        Q <= D;
end

endmodule
